import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Github, Linkedin } from 'lucide-react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

const Navbar: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id: string) => {
    if (location.pathname !== '/') {
      navigate('/');
      setTimeout(() => {
        document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-[#030014]/80 backdrop-blur-xl border-b border-white/10 py-4' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
        <Link to="/" className="flex items-center space-x-2">
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="flex items-center space-x-3 cursor-pointer"
          >
            <div className="w-10 h-10 bg-gradient-to-br from-purple-600 to-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-lg shadow-purple-500/20 text-white">
              V
            </div>
            <span className="text-xl font-display font-bold tracking-tight hidden sm:block text-white">Viren Pandey</span>
          </motion.div>
        </Link>

        <motion.div 
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          className="flex items-center space-x-8"
        >
          <button onClick={() => scrollTo('projects')} className="text-sm font-medium text-gray-400 hover:text-white transition-colors">Projects</button>
          <button onClick={() => scrollTo('skills')} className="text-sm font-medium text-gray-400 hover:text-white transition-colors">Skills</button>
          <Link to="/blog" className="text-sm font-medium text-gray-400 hover:text-white transition-colors">Blog</Link>
          <Link to="/login" className="text-sm font-medium text-gray-400 hover:text-white transition-colors">Login</Link>
          <div className="w-px h-4 bg-white/20" />
          <div className="flex space-x-4">
            <a href="https://github.com/viren-pandey" target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-white transition-colors">
                <Github size={20} />
            </a>
            <a href="https://linkedin.com/in/viren-pandey" target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-white transition-colors">
                <Linkedin size={20} />
            </a>
          </div>
        </motion.div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
import Hero from '../components/Hero';
import Skills from '../components/Skills';
import Projects from '../components/Projects';
import Education from '../components/Education';

const Home: React.FC = () => {
  return (
    <>
      <Hero />
      <section id="skills" className="py-24 relative">
         <div className="absolute inset-0 bg-gradient-to-b from-transparent via-purple-900/5 to-transparent pointer-events-none" />
        <Skills />
      </section>
      <section id="projects" className="py-24 relative">
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-blue-900/5 to-transparent pointer-events-none" />
        <Projects />
      </section>
      <section id="education" className="py-24 relative">
        <Education />
      </section>
    </>
  );
};

export default Home;
